namespace sv_267eaf7b226d47289985d116814431e0.Models;

public class WizardState
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public ExperienceInfo Experience { get; set; } = new();
    public ReferencesInfo References { get; set; } = new();
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class PersonalInfo
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class ExperienceInfo
{
    public List<JobEntry> Jobs { get; set; } = [];
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferencesInfo
{
    public List<ReferenceContact> Contacts { get; set; } = [];
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_267eaf7b226d47289985d116814431e0.Models;

namespace sv_267eaf7b226d47289985d116814431e0.Services;

/// <summary>
/// Singleton, in-memory store for wizard state keyed by session ID.
/// Both static (SSR) and interactive (Server) components share this instance,
/// bridging the render-mode boundary.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId) =>
        _states.GetOrAdd(sessionId, _ => new WizardState());

    public void Remove(string sessionId) =>
        _states.TryRemove(sessionId, out _);
}

@inherits LayoutComponentBase
@layout MainLayout
@using sv_267eaf7b226d47289985d116814431e0.Services
@inject WizardStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor

@{
    var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    var state = StateStore.GetOrCreate(sessionId);
    var currentStep = GetCurrentStep();
}

<CascadingValue Value="sessionId" Name="WizardSessionId">
    <nav class="wizard-progress mb-4">
        <h5 class="mb-3">Job Application — Step @currentStep of 4</h5>
        <div class="d-flex gap-2">
            @for (int i = 1; i <= 4; i++)
            {
                var step = i;
                var isCurrent = step == currentStep;
                var isCompleted = state.CompletedSteps.Contains(step);
                var css = isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary";
                <a href="@StepUrl(step)" class="btn @css btn-sm flex-fill text-center">
                    @StepLabel(step)
                    @if (isCompleted) { <span>✓</span> }
                </a>
            }
        </div>
    </nav>

    @Body
</CascadingValue>

@code {
    private int GetCurrentStep()
    {
        var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
        return path switch
        {
            "/apply/experience" => 2,
            "/apply/references" => 3,
            "/apply/review" => 4,
            _ => 1
        };
    }

    private static string StepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/apply/personal-info"
    };

    private static string StepLabel(int step) => step switch
    {
        1 => "Personal Info",
        2 => "Experience",
        3 => "References",
        4 => "Review",
        _ => ""
    };
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@using sv_267eaf7b226d47289985d116814431e0.Models
@using sv_267eaf7b226d47289985d116814431e0.Services
@using sv_267eaf7b226d47289985d116814431e0.Components.Layout
@inject WizardStateStore StateStore
@inject NavigationManager Nav

<PageTitle>Personal Info</PageTitle>

<h3>Personal Information</h3>

<EditForm Model="_model" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="_model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    [CascadingParameter(Name = "WizardSessionId")]
    private string SessionId { get; set; } = "";

    private Models.PersonalInfo _model = new();

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionId))
        {
            var state = StateStore.GetOrCreate(SessionId);
            _model = new Models.PersonalInfo
            {
                Name = state.PersonalInfo.Name,
                Email = state.PersonalInfo.Email
            };
        }
    }

    private void Next()
    {
        var state = StateStore.GetOrCreate(SessionId);
        state.PersonalInfo.Name = _model.Name;
        state.PersonalInfo.Email = _model.Email;
        state.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@using sv_267eaf7b226d47289985d116814431e0.Models
@using sv_267eaf7b226d47289985d116814431e0.Services
@using sv_267eaf7b226d47289985d116814431e0.Components.Layout
@inject WizardStateStore StateStore
@inject NavigationManager Nav

<PageTitle>Experience</PageTitle>

<h3>Work Experience</h3>

@for (int i = 0; i < _jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Job @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="_jobs[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="_jobs[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="_jobs[index].Years" />
        </div>
    </div>
}

<div class="mb-3">
    <button type="button" class="btn btn-outline-primary" @onclick="AddJob">+ Add Job</button>
</div>

<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-secondary">← Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    [CascadingParameter(Name = "WizardSessionId")]
    private string SessionId { get; set; } = "";

    private List<JobEntry> _jobs = [];

