using System.Collections.Concurrent;
using sv_267eaf7b226d47289985d116814431e0.Models;

namespace sv_267eaf7b226d47289985d116814431e0.Services;

/// <summary>
/// Singleton, in-memory store for wizard state keyed by session ID.
/// Both static (SSR) and interactive (Server) components share this instance,
/// bridging the render-mode boundary.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId) =>
        _states.GetOrAdd(sessionId, _ => new WizardState());

    public void Remove(string sessionId) =>
        _states.TryRemove(sessionId, out _);
}

@inherits LayoutComponentBase
@layout MainLayout
@using sv_267eaf7b226d47289985d116814431e0.Services
@inject WizardStateStore StateStore
@inject IHttpContextAccessor HttpContextAccessor

@{
    var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSessionId"] ?? "";
    var state = StateStore.GetOrCreate(sessionId);
    var currentStep = GetCurrentStep();
}

<CascadingValue Value="sessionId" Name="WizardSessionId">
    <nav class="wizard-progress mb-4">
        <h5 class="mb-3">Job Application — Step @currentStep of 4</h5>
        <div class="d-flex gap-2">
            @for (int i = 1; i <= 4; i++)
            {
                var step = i;
                var isCurrent = step == currentStep;
                var isCompleted = state.CompletedSteps.Contains(step);
                var css = isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary";
                <a href="@StepUrl(step)" class="btn @css btn-sm flex-fill text-center">
                    @StepLabel(step)
                    @if (isCompleted) { <span>✓</span> }
                </a>
            }
        </div>
    </nav>

    @Body
</CascadingValue>

@code {
    private int GetCurrentStep()
    {
        var path = HttpContextAccessor.HttpContext?.Request.Path.Value ?? "";
        return path switch
        {
            "/apply/experience" => 2,
            "/apply/references" => 3,
            "/apply/review" => 4,
            _ => 1
        };
    }

    private static string StepUrl(int step) => step switch
    {
        1 => "/apply/personal-info",
        2 => "/apply/experience",
        3 => "/apply/references",
        4 => "/apply/review",
        _ => "/apply/personal-info"
    };

    private static string StepLabel(int step) => step switch
    {
        1 => "Personal Info",
        2 => "Experience",
        3 => "References",
        4 => "Review",
        _ => ""
    };
}

