@inject NavigationManager Nav

<PageTitle>Personal Info</PageTitle>

<h3>Personal Information</h3>

<EditForm Model="_model" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="_model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    [CascadingParameter(Name = "WizardSessionId")]
    private string SessionId { get; set; } = "";

    private Models.PersonalInfo _model = new();

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionId))
        {
            var state = StateStore.GetOrCreate(SessionId);
            _model = new Models.PersonalInfo
            {
                Name = state.PersonalInfo.Name,
                Email = state.PersonalInfo.Email
            };
        }
    }

    private void Next()
    {
        var state = StateStore.GetOrCreate(SessionId);
        state.PersonalInfo.Name = _model.Name;
        state.PersonalInfo.Email = _model.Email;
        state.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

