@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@using sv_267eaf7b226d47289985d116814431e0.Models
@using sv_267eaf7b226d47289985d116814431e0.Services
@using sv_267eaf7b226d47289985d116814431e0.Components.Layout
@inject WizardStateStore StateStore
@inject NavigationManager Nav

<PageTitle>Experience</PageTitle>

<h3>Work Experience</h3>

@for (int i = 0; i < _jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Job @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="_jobs[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="_jobs[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="_jobs[index].Years" />
        </div>
    </div>
}

<div class="mb-3">
    <button type="button" class="btn btn-outline-primary" @onclick="AddJob">+ Add Job</button>
</div>

<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-secondary">← Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    [CascadingParameter(Name = "WizardSessionId")]
    private string SessionId { get; set; } = "";

    private List<JobEntry> _jobs = [];

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionId))
        {
            var state = StateStore.GetOrCreate(SessionId);
            _jobs = state.Experience.Jobs
                .Select(j => new JobEntry { Company = j.Company, Title = j.Title, Years = j.Years })
                .ToList();
        }
        if (_jobs.Count == 0)
            _jobs.Add(new JobEntry());
    }

    private void AddJob() => _jobs.Add(new JobEntry());
    private void RemoveJob(int index) { if (_jobs.Count > 1) _jobs.RemoveAt(index); }

    private void Next()
    {
        var state = StateStore.GetOrCreate(SessionId);
        state.Experience.Jobs = _jobs
            .Select(j => new JobEntry { Company = j.Company, Title = j.Title, Years = j.Years })
            .ToList();
        state.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout WizardLayout
@using sv_267eaf7b226d47289985d116814431e0.Models
@using sv_267eaf7b226d47289985d116814431e0.Services
@using sv_267eaf7b226d47289985d116814431e0.Components.Layout
@inject WizardStateStore StateStore
@inject NavigationManager Nav

<PageTitle>References</PageTitle>

<h3>References</h3>

@for (int i = 0; i < _contacts.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Reference @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveContact(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="_contacts[index].Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Email</label>
            <input class="form-control" @bind="_contacts[index].Email" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="_contacts[index].Relationship" />
        </div>
    </div>
}

<div class="mb-3">
    <button type="button" class="btn btn-outline-primary" @onclick="AddContact">+ Add Reference</button>
</div>

<div class="d-flex gap-2">
    <a href="/apply/experience" class="btn btn-secondary">← Back</a>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    [CascadingParameter(Name = "WizardSessionId")]
    private string SessionId { get; set; } = "";

    private List<ReferenceContact> _contacts = [];

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionId))
        {
            var state = StateStore.GetOrCreate(SessionId);
            _contacts = state.References.Contacts
                .Select(c => new ReferenceContact { Name = c.Name, Email = c.Email, Relationship = c.Relationship })
                .ToList();
        }
        if (_contacts.Count == 0)
            _contacts.Add(new ReferenceContact());
    }

    private void AddContact() => _contacts.Add(new ReferenceContact());
    private void RemoveContact(int index) { if (_contacts.Count > 1) _contacts.RemoveAt(index); }

    private void Next()
    {
        var state = StateStore.GetOrCreate(SessionId);
        state.References.Contacts = _contacts
            .Select(c => new ReferenceContact { Name = c.Name, Email = c.Email, Relationship = c.Relationship })
            .ToList();
        state.CompletedSteps.Add(3);
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout
@using sv_267eaf7b226d47289985d116814431e0.Models
@using sv_267eaf7b226d47289985d116814431e0.Services
@using sv_267eaf7b226d47289985d116814431e0.Components.Layout
@inject WizardStateStore StateStore
@inject NavigationManager Nav

<PageTitle>Review Application</PageTitle>

<h3>Review Your Application</h3>

@if (_state is not null)
{
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @_state.PersonalInfo.Name</p>
        <p><strong>Email:</strong> @_state.PersonalInfo.Email</p>
    </div>

    <div class="card mb-3 p-3">
        <h5>Work Experience</h5>
        @if (_state.Experience.Jobs.Count == 0)
        {
            <p class="text-muted">No jobs entered.</p>
        }
        else
        {
            @foreach (var job in _state.Experience.Jobs)
            {
                <div class="mb-2">
                    <strong>@job.Title</strong> at @job.Company (@job.Years years)
                </div>
            }
        }
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (_state.References.Contacts.Count == 0)
        {
            <p class="text-muted">No references entered.</p>
        }
        else
        {
            @foreach (var contact in _state.References.Contacts)
            {
                <div class="mb-2">
                    <strong>@contact.Name</strong> — @contact.Email (@contact.Relationship)
                </div>
            }
        }
    </div>

    <div class="d-flex gap-2">
        <a href="/apply/references" class="btn btn-secondary">← Back</a>
        <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>
}

@code {
    [CascadingParameter(Name = "WizardSessionId")]
    private string SessionId { get; set; } = "";

    private WizardState? _state;

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(SessionId))
            _state = StateStore.GetOrCreate(SessionId);
    }

    private void Submit()
    {
        _state?.CompletedSteps.Add(4);
        // In a real app, persist the application to a database here.
        Nav.NavigateTo("/");
    }
}

